                            <template v-slot:tgslot-isCDCMapping="{ data }">
                                <div class="col-sm-12 col-md-12 col-lg-12 col-xl-12 float-left pl-2 mb-2 " >
                                      
                                      <div class="form-group">
                                          <label class="d-flex"><span>{{$t('CDC Mapping')}}:</span>
                                       
