                            </template>

                            <template v-slot:tgslot-isSBA="{ data }">

<div class="col-sm-12 col-md-12 col-lg-12 col-xl-12 float-left pl-2 mb-2 " >
                                      
                                      <div class="form-group">
                                          <label class="d-flex"><span>{{$t('SBA')}}:</span>
                                       
                                                <span id="spnSBA"  class="noti-circle noti-green ml-1 noti-clients ml-2">{{ getFieldCount('isSBA') }} </span>
                                                    
                                            </label>

                                                 <div class="form-group mb-0 mt-2">
                                              <label class="switch p-0">
                                        <input
                                            type="checkbox"
                                            v-model="CloneSetupList.isSBA"
                                        >
                                        <span class="slider round">
