        </div>
    </div>
    <!-- <transition name="modal"> -->






  


<div class="my-popups" v-if="isUtlities">
        <loader :is-visible="isLoading"></loader>

        <div class="modal my-popups right fade d-block" :class="{ show: isShown }">
            <div role="document" class="modal-dialog" style="max-width: 800px !important;">
                <div class="modal-content">

                    <!-- HEADER -->
                    <div class="modal-header theme-primary partition-full d-flex">
                         <h4 class="modal-title">{{ $t("SelectUtilities") }}</h4>
                         
                        <button type="button" class="close" @click="CloseUtlities()">
                            <em class="fa fa-times"></em>
                        </button>
                    </div>

                    <!-- BODY -->
                    <div class="modal-body">

                            <div class="tab-content">
                        <!-- SEARCH -->
                        <div class="tab-pane active show">


                            <div></div>
                        <tg-list :IsShowAction="false"  
    :isShowHeaderText="false" ModuleName="Client" SubModuleCode="Client" :LegendArray="[]" :RenderRowActionMethod="renderActions" @ActionButtonClick="actionButtonClick" :widgets="[]" 
                        IdentityColumn="CLIENT_ADDITIONAL_ID" :listType="['List']" :ListData="AvailbleUtilities" :HeaderData="Headers" :HeaderButtons="listheaderbuttons" :TotalRecords="TotalRecords" 
                        :SearchFields="topSearchFields" :IsSearchFieldsOnTop="false" SearchPosition="top" :ListDataCallBackFunction="GetUtilityByClientId" :showCheckBox="true" :SortExp="SortExp" 
                        :SortBy="SortBy" :NorecordfoundText="$t('NoRecordfound')" :HeaderText="null" @LeftsearchButtonClick="leftCommonSearch" @PagerButtonClick="pagerMethod" 
                        @HeaderButtonClick="commonHeaderButtonClick" @SortdataButtonClick="sortdata" >
                            
                        </tg-list>


                            
                        </div>
                        </div>

                        <!-- TABLE -->
<div class="modal-footer">
                        <div class="col-lg-6 text-right p-0">
                            <a href="javascript:;" class="btn btn-primary formbtn text-white mr-2" v-on:click="Next()">    
                                <em class="fa fa-forward"></em>
                                {{ $t("Next") }}
                            </a>

                            <a href="javascript:;" 
                            class="btn btn-danger formbtn text-white" v-on:click="CloseUtlities()">
                                <em class="fa fa-close pr-2"></em>
                                {{ $t("Cancel") }}
                            </a>
                        </div>
                    </div>
                    </div>
                </div>
            </div>
        </div>
    </div>
</div>

<div  v-if="showConfirm">
<div  class="modal my-popups fade d-block" :class="{ show: isShown }">
  <div role="document" class="modal-dialog">
    <div class="modal-content">

      <!-- Modal Body -->
      <div class="modal-body alert-warning">
        {{$t("ConfirmAlreadyExistsCLientSetupOption")}}
      </div>

      <!-- Modal Footer -->
      <div style="flex-wrap: inherit;" aria-required="false" class="modal-footer modal-confirm-footer">
        <button type="button" title="Yes" class="btn btn-success" @click="onYes">
          <i class="fa fa-check pr-2"></i>Yes
        </button>

        <button type="button" title="No" class="btn btn-danger" @click="onNo">
          <i class="fa fa-close pr-2"></i>No
        </button>

        <button type="button" title="Cancel" class="btn btn-danger" @click="onCancel">
          <i class="fa fa-close pr-2"></i>Cancel
        </button>
      </div>
</div>
    </div>
  </div>
</div>
 
 
    </div>
</section>
</template>

<script>
import DataService from '../../services/DataService';
//import ConfirmDialogModel from '../Modals/ConfirmDialogModel.vue';
export default {
   // components: { ConfirmDialogModel },
    props: {
        ClientId: {
            type: Number,
            required: true,
        },
        UtilityIds: {
            type: Number,
            required: false,
        }
    },
    data() {
        return {
            listheaderbuttons: [],
            isLoading: false,
            isShown: false,
            isUtlities: false,
            contractName: '',
            clientList: [],
            isFetchingClients: false,
            BillerItemsList: [],
            UserId: '',
            receivedData: [], // ✅ REQUIRED
            BindUtilityName: '',
            UtilityList: [],
            AvailbleUtilities: [],
            SortBy: '',
            SortExp: '',
            PageSize: 10,
            PageNumber: 1,
            TotalRecords: 0,
            CurrentPage: 1,
            TotalPages: 0,
            noRecords: false,
            utilityIds:'',
           CloneSetupList: {
                isBillingRule: false,
                isCDCMapping: false,
                isCompanyHoliday: false,
                isInvoiceGrouping: false,
                isRateSchedule: false,
                isSBA: false,
                isTalygenUtility: true
            },
            showConfirm: false,
            pendingFormFields: {}, // store the copy of formfields
            FormSchema: [{

                    layoutType: "double",
                    Data: [{
                            astype: "SearchableSelectField",
                            label: this.$t('ContractCompanyName'),
                            name: "ContractName",
                            value: "",
                            placeholder: "Select",
                            visibility: true,
                            isSearch: false,
                            config: {
                                options: [],
                                actionButtons: {
                                    selectAll: false,
                                    active: false,
                                    inactive: false,
                                    clear: false
                                },
                                isMultiple: false,
                                groupFields: ['groupText'],
                                minSearchLength: 0,
                                statusFieldConfig: {
                                    fieldName: 'status',
                                    activeValues: ['Active', 'active'],
                                    inactiveValues: ['Inactive', 'inactive'],
                                    activeColor: '#28a745',
                                    inactiveColor: '#dc3545'
                                },
                                onChange: this.onSelectionChange
                            },
                            disabled: false,
                            validationRules: {
                                "required": true
                            },
                        },
                       
                    ],
                },
                {
                    group_name: this.$t('ContractSetup'),
                    layoutType: "single",
                    Data: [
                        {
                        astype: "toggleField",
                        label: this.$t('SelectAll'),
                        name: "isSelect",
                        value: false,
                        config: {
                            onChange: this.onSelectAllChange,
                        },
                    }, 
                ]
                },
                {                    
                    layoutType: "four",
                    Data: [
                        {    
                            astype: "SlotField",
                            //label: this.$t('TalygenUtility'),
                            name: "isTalygenUtility",
                            value: true
                            
                        },
                        {
                            astype: "SlotField",
                            //label: this.$t('RateSchedule'),
                            name: "isRateSchedule",
                            value: false
                        },
                        {
                            astype: "SlotField",
                            //label: this.$t('BillingRule'),
                            name: "isBillingRule",
                            value: false
                        },
                        {
                            astype: "SlotField",
                            //label: this.$t('InvoiceGrouping'),
                            name: "isInvoiceGrouping",
                            value: false
                        },
                        {
                            astype: "SlotField",
                            //label: this.$t('CDCMapping'),
                            name: "isCDCMapping",
                            value: false
                        },
                        {
                            astype: "SlotField",
                            //label: this.$t('CompanyHoliday'),
                            name: "isCompanyHoliday",
                            value: false
                        },
                        {
                            astype: "SlotField",
                            //label: this.$t('SBA'),
                            name: "isSBA",
                            value: false
                        }
                    ]
                }


                
            ],
            buttons: [{
                    type: "submit",
                    class: "btn btn-success",
                    text: "<i class='fa fa-save pr-2'></i>" + this.$t('CloneContractSetup'),
                    onClick: this.CreateClone
                },
                {
                    type: "button",
                    class: "btn btn-danger",
                    text: "<i class='fa fa-close pr-2'></i>" + this.$t('Cancel'),
                    onClick: this.Close,
                },
            ],
            Headers: [{
                "COLUMN_NAME": "COMPANY_NAME",
                "DATA_TYPE": "text",
                "SORTABLE": false,
                "VISIBLE": true,
                "DISPLAY_NAME": 'Utility Name',
                "DISPLAY_ORDER": 1,
                settings: {
                    isInSlot: false
                }
            }, ],
        }
    },
    mounted() {
        this.$nextTick(() => {
            setTimeout(() => {
                this.isShown = true; // adds .show ? triggers transform transition
            }, 50);
        });
    },
    computed: {
        fieldCountMap() {
            const map = {};
            const data = this.FormSchema?.[2]?.Data || [];
            data.forEach(field => {
                map[field.name] = field.count || 0;
            });
            return map;
        }
    },    
    created: async function () {        
        var vm = this;
        vm.UserId = vm.GetUserInfo.ID;
        await vm.GetDDLCompanyContractClients();
        await vm.FetchData();
        vm.GetUtilityByClientId(false);
        //vm.FormSchema[0].Data[0].value=vm.ClientId;       
    },
    methods: {
        
        GetDDLCompanyContractClients: async function () {
            var vm = this;
            vm.isLoading = true;
            var url = `reqFrom=CUSTOM`;
            await DataService.getClientList(url).then(response => {
                vm.isLoading = false;
                vm.clientList = response.data.items.filter(
                    item => Number(item.value) !== Number(vm.ClientId)
                );
                vm.$refs.CloneSetup.updateProperty("ContractName", "config.options", vm.clientList);
                vm.$refs.CloneSetup.UpdateKeyValue();
            }).catch(error => {
                vm.isLoading = false;
                vm.clientList = [];
                vm.$refs.CloneSetup.updateProperty("ContractName", "config.options", vm.clientList);
                vm.$refs.CloneSetup.UpdateKeyValue();
                console.error('Error fetching client list:', error);
            }).finally(() => {
                vm.isLoading = false;
            });
        },     

        onSelectAllChange() {
            const value = this.FormSchema[1].Data[0].value; // Select All toggle value

            

            Object.keys(this.CloneSetupList).forEach(key => {
                this.$set(this.CloneSetupList, key, value);
            });
             this.$set(this.CloneSetupList, 'isTalygenUtility', true);
        },

        FetchData: async function () {
           
            const vm = this;
             vm.isLoading=true;
            const url = `clientId=${vm.ClientId}&utilityIds=${vm.utilityIds}`;

            try {
                const response = await DataService.CopyClientSetup(url);

                if (response.status === 200 && Array.isArray(response.data)) {
                    const item = response.data[0];
                    vm.ClientItemsList = item;
                    
                    if(item.TalygenUtilityRecordsCount===0)
                    {
                    vm.buttons[0].class += " disabled";
                    }
                    const fields = vm.FormSchema[2].Data;
                    fields.forEach(f => {
                        let count = 0;
                        switch (f.name) {
                            case "isTalygenUtility":
                                count = item.TalygenUtilityRecordsCount;
                                break;
                            case "isRateSchedule":
                                count = item.RateScheduleRecordsCount;
                                break;
                            case "isBillingRule":
                                count = item.BillingRulesRecordsCount;
                                break;
                            case "isInvoiceGrouping":
                                count = item.InvoiceGroupingRecordsCount;
                                break;
                            case "isCDCMapping":
                                count = item.CDCMappingRecordsCount;
                                break;
                            case "isCompanyHoliday":
                                count = item.CompanyHolidayRecordsCount;
                                break;
                            case "isSBA":
                                count = item.SBARecordsCount;
                                break;
                        }
                        // Vue 2 reactive safe update
                        vm.$set(f, "count", count || 0);
                    });
                }
                vm.isLoading=false;

            } catch (error) {
                console.error("Error in FetchData:", error);
            }
        },


        GetUtilityByClientId: function (val) {
            
            const vm = this;
            const url = `clientId=${vm.ClientId}`;
           
            DataService.GetUtilityByClientId(url).then((response) => {
                
                vm.isUtlities = val;
                try {
                    if (response?.data) {
                        vm.AvailbleUtilities = (response?.data || "null");                        
                        vm.isLoading = false;
                    } else {
                        vm.AvailbleUtilities = [];
                        vm.noRecords = true;
                        vm.TotalRecords = 0
                        vm.isLoading = false;
                    }
                } catch (e) {
                    console.error("Error parsing contract result:", e);
                }
            })
        },
    
        SubmitData(formfields, val) {
            //debugger;
            
            const vm = this;
           
            vm.saveClone("", formfields);
            
        },
        
        

  onYes() {
    //debugger
    //console.log("Yes clicked");
     this.saveClone("YES", this.pendingFormFields);
    this.showConfirm = false;
  },
  onNo() {
    //debugger
    //console.log("No clicked");
    this.showConfirm = false;
     this.saveClone("NO", this.pendingFormFields);
  },
  onCancel() {
    //debugger
    console.log("Cancel clicked");
    this.showConfirm = false;
  },
        saveClone(confirmDeleteType, formfields) {
            debugger;
            const vm = this;
            const cloneSetupArr = [];

            if (vm.CloneSetupList.isTalygenUtility) cloneSetupArr.push('TalygenUtility');
            if (vm.CloneSetupList.isRateSchedule) cloneSetupArr.push('RateSchedule');
            if (vm.CloneSetupList.isInvoiceGrouping) cloneSetupArr.push('InvoiceGrouping');
            if (vm.CloneSetupList.isSBA) cloneSetupArr.push('SBA');
            if (vm.CloneSetupList.isBillingRule) cloneSetupArr.push('BillingRules');
            if (vm.CloneSetupList.isCompanyHoliday) cloneSetupArr.push('CompanyHoliday');
            if (vm.CloneSetupList.isCDCMapping) cloneSetupArr.push('CDC');

            // 🚨 Mandatory check
            if (!cloneSetupArr.includes('TalygenUtility')) {
                vm.ShowAlert(vm.$t('Talygen Utility is required for clone'),"warning", true, vm.$t('Alert'));
                return;
            }            

            if (!vm.utilityIds) {
                vm.utilityIds = vm.AvailbleUtilities?.map(u => u.CLIENT_ADDITIONAL_ID).filter(Boolean).join(",");
            } 
            /* ------------------------------------------
            Prepare payload
            ------------------------------------------ */
            const payload = {
                fromClientId: vm.ClientId,
                targetClientId: formfields.ContractName,
                cloneClientSetup: cloneSetupArr.join(','), // ✅ string only here
                utilityIds: vm.utilityIds,
                cloneType: "Copy",
                confirmDeleteType: confirmDeleteType || ""
            };

            /* ------------------------------------------
            API Call
            ------------------------------------------ */
            vm.isLoading = true;

            DataService.SaveCloneSetup(JSON.stringify(payload))
                .then(response => {
                    //debugger;
                 let resultObj = JSON.parse(response.data?.result);
                    //const status = response?.data?.status || response?.data?.Status;
                    //const statusalreadyExists =  response?.data?.Result;
                   if (resultObj.MSG === "SUCCESS" && resultObj.TRACKALREADYEXIXTS === "") 
                   {
                        vm.ShowAlert(vm.$t('AddedSuccess', [vm.$t('Copy')]),"success",true,vm.$t('Alert'));
                        vm.$parent.FetchRecords();
                        vm.Close();
                    } 
                    else if(resultObj.MSG === "SUCCESS" && resultObj.TRACKALREADYEXIXTS!=="")
                    {
                       // debugger;
                        this.pendingFormFields=formfields;
                        this.showConfirm=true;
                        //debugger;
                        
                    }
                    
                    else {
                        vm.ShowAlert(
                            vm.$t("ErrorWhileSaving"),"danger",true,vm.$t("Alert")
                        );
                    }
                })
                .catch(error => {
                    vm.ShowAlert(vm.$t("ErrorWhileSaving"),"danger",true,vm.$t("Alert"));
                    console.error('Clone setup error:', error);
                })
                .finally(() => {
                    vm.isLoading = false;
                });
        },
        Next() {
            //debugger;
            const vm = this;
            const selectedUtilityIds = [];
            $('.chkItems:checkbox:checked').not("[id^='chkAll']")
                .each(function () {
                    selectedUtilityIds.push($(this).val());
                });

            const count = selectedUtilityIds.length;
            if (count > 0) {
                const fields = vm.FormSchema[2].Data;
                    fields.forEach(f => {
                        if (f.name === "isTalygenUtility") {
                            f.count = count;     
                        }
                    });
                vm.utilityIds = selectedUtilityIds.join(",");
                this.FetchData(); 
                vm.isUtlities = false;
            } else {
                vm.utilityIds = '';
            }
        },


        Close: function () {
            this.$parent.CloneSetupPopup = false;
        },
        CloseUtlities: function () {
            var vm=this;
            vm.isUtlities = false;
        },
        leftCommonSearch: function (value) {
            this.PageNumber = value.PageNumber;
            this.isPaged = 1;

            if (typeof value.searchConditionJson !== 'undefined') {
                this.searchCondition = value.searchConditionJson.split('=')[1] || '';
            } else {
                this.searchCondition = "";
            }
            this.GetUtilityByClientId();
        },
        commonHeaderButtonClick: function (event) {
            switch (event.callbackfunction) {

            }
        },

        sortdata: function (sortBy) {
            this.SortBy = sortBy;
            var sortExp = 'ASC';
            if (this.SortExp == 'ASC') {
                sortExp = 'DESC';
            }
            this.SortExp = sortExp;
            this.SortBy = sortBy;
            this.SortExp = sortExp;
            this.PageNumber = 1;
            this.FetchData();
        },
        pagerMethod: function (value) {
            this.PageSize = value.PageSize;
            this.PageNumber = value.PageNumber;
            this.FetchData();
        },
        renderActions: function (row) {
            var self = this;
            let rtnActionArray = [];
            return rtnActionArray;
        },
        actionButtonClick: function (callbackfunction, item) {
            switch (callbackfunction) {

            }
        },        
       getFieldByName(fieldName) {
            return this.FormSchema?.[2]?.Data?.find(f => f.name === fieldName) || null;
        },

        getFieldCount(fieldName) {
            const field = this.getFieldByName(fieldName);
            return field && field.count ? field.count : 0;
        },

        handleBadgeClickByName(fieldName) {
            const field = this.FormSchema?.[2]?.Data?.find(f => f.name === fieldName);

            if (!field || field.count === 0) return;

            this.handleBadgeClick(field);
        },
        handleBadgeClick(field) {
            if (!field.count) return;

            const actionMap = {
                isTalygenUtility: () => this.GetUtilityByClientId(true),
                isBillingRule: () => this.openBillingRuleModal(),
                isRateSchedule: () => this.openRateScheduleModal(),
                isInvoiceGrouping: () => this.openInvoiceGroupingModal(),
                isCompanyHoliday: () => this.openCompanyHolidayModal(),
                isCDCMapping: () => this.openCDCModal(),
                isSBA: () => this.openSBAModal()
            };

            actionMap[field.name]?.();
        },
    }
}
</script>


